mapper.select:
select 
from portfolio.publication
where aggregate_type = #{type} and aggregate_id = #{aggregateId}

select 
from portfolio.publication
where aggregate_type = 'PROJECT' and status = 'PUBLISHED' and current_slug = #{slug}

mapper.update:
update portfolio.publication
set status='PUBLISHED', current_revision_id=#{revisionId}, current_slug=#{slug},
    version=version+1, published_at=#{publishedAt}
where aggregate_type=#{type} and aggregate_id=#{aggregateId} and version=#{expectedVersion}

update portfolio.publication
set status='ARCHIVED', version=version+1, published_at=#{archivedAt}
where aggregate_type=#{type} and aggregate_id=#{aggregateId} and version=#{expectedVersion}

mapper.select:
select exists (
  select 1 from portfolio.publication
  where aggregate_type='PROJECT'
    and current_slug=#{slug} and aggregate_id<>#{excludingProjectId}
  union
  select 1 from portfolio.slug_redirect
  where old_slug=#{slug}
)
